// 主页图片三维活动
var moveForce = 45;
var rotateForce = 30;
$(window).mousemove(function(e) {
	var docX = $(window).width();
	var docY = $(window).height(); 
	var moveX = (e.pageX - docX/2) / (docX/2) * -moveForce;
	var moveY = (e.pageY - docY/2) / (docY/2) * -moveForce;	
	var rotateY = (e.pageX / docX * rotateForce*2) - rotateForce;
	var rotateX = -((e.pageY / docY * rotateForce*2) - rotateForce);	
	$('.popup')
		.css('left', moveX+'px')
		.css('top', moveY+'px')
		.css('transform', 'rotateX('+rotateX+'deg) rotateY('+rotateY+'deg)');
});	
// 主页图片幻灯片
$(function () {
	$('.images').hubSlider({
		selector: $('.images img'),
		button: {
			next: $('.hub-slider-arrow_next'),
			prev: $('.hub-slider-arrow_prev')
		},
		transition: '0.7s',
		startOffset: 30,
		auto: true,
		time: 5 // secondly
	});
})
// 文章页图片放大灯箱
$(document).ready(function() {
	// 当在.article>article p内的img上点击时触发的事件
	$("#Changelog img").on("click", function(event) {
		// 阻止事件的冒泡，确保其他的点击事件监听器不会被触发
		event.stopPropagation();
		// 创建一个空的div并赋予它"bg"类名
		var emptyDiv = $("<div></div>").addClass("bg");
		// 将空的div添加到body
		$("body").append(emptyDiv);
		// 克隆点击的图片
		var clonedImage = $(this).clone();
		// 创建一个新的div，并将克隆的图片添加到这个div中，同时给这个div赋予"DX"类名
		var newDiv = $("<div></div>").addClass("DX").append(clonedImage);
		// 将新的div添加到body
		$("body").append(newDiv);
		// 使用setTimeout确保CSS变化是在元素加入DOM后发生的
		// 在1毫秒后（基本上是立即执行），设置newDiv的透明度和缩放效果
		setTimeout(function() {
			newDiv.css({
				'opacity': '1',
				'transform': 'none'
			});
		}, 1); 
	});
	// 当点击文档的任何位置时触发的事件
	$(document).on("click", function() {
		// 设置DX类的div的透明度和缩放效果，使其淡出并缩小
		$(".DX").css({
			'opacity': '0',
			'transform': 'scale(0)'
		});
		// 在动画结束后（即300毫秒后），移除DX类的div和bg类的div
		setTimeout(function() {
			$(".DX").remove();
			$(".bg").remove();
		}, 300);
	});
});